# Stripe configuration - will be set dynamically based on mode
def get_stripe_keys():
    """Get Stripe keys based on the current mode setting"""
    # Get the mode from environment variable or site settings (default to 'test' for safety)
    stripe_mode = os.environ.get('STRIPE_MODE')
    if not stripe_mode:
        stripe_mode = get_site_setting('stripe_mode', 'test')

    if stripe_mode == 'live':
        # Use live keys
        secret_key = os.environ.get('STRIPE_LIVE_SECRET_KEY')
        publishable_key = os.environ.get('STRIPE_LIVE_PUBLISHABLE_KEY')
        webhook_secret = os.environ.get('STRIPE_LIVE_WEBHOOK_SECRET')
    else:
        # Use test keys (default)
        secret_key = os.environ.get('STRIPE_TEST_SECRET_KEY')
        publishable_key = os.environ.get('STRIPE_TEST_PUBLISHABLE_KEY')
        webhook_secret = os.environ.get('STRIPE_TEST_WEBHOOK_SECRET')

    # Fallback to legacy keys if specific mode keys not set
    if not secret_key:
        secret_key = os.environ.get('STRIPE_SECRET_KEY')
    if not publishable_key:
        publishable_key = os.environ.get('STRIPE_PUBLISHABLE_KEY')
    if not webhook_secret:
        webhook_secret = os.environ.get('STRIPE_WEBHOOK_SECRET')

    return {
        'secret_key': secret_key,
        'publishable_key': publishable_key,
        'webhook_secret': webhook_secret,
        'mode': stripe_mode
    }

def init_stripe():
    """Initialize Stripe with the appropriate keys"""
    try:
        keys = get_stripe_keys()
        if keys and keys['secret_key']:
            stripe.api_key = keys['secret_key']
            print(f"DEBUG: Initialized Stripe in {keys['mode']} mode")
            return keys
        else:
            print("DEBUG: Stripe keys not found in get_stripe_keys")
    except Exception as e:
        print(f"DEBUG: init_stripe error: {str(e)}")
    
    # Fallback for initial setup before DB is ready or if keys missing
    stripe.api_key = os.environ.get('STRIPE_LIVE_SECRET_KEY') or os.environ.get('STRIPE_SECRET_KEY') or os.environ.get('STRIPE_TEST_SECRET_KEY')
    print(f"DEBUG: Stripe initialized using fallback")
    return None

