def _apply_referral_credit(referral_record, referred_user):
    """Credit RM5 referral bonus to the referrer's wallet. Call inside an active db.session."""
    referrer_wallet = Wallet.query.filter_by(user_id=referral_record.referrer_id).first()
    if not referrer_wallet:
        return
    bonus = referral_record.bonus_amount
    balance_before = referrer_wallet.balance
    referrer_wallet.balance += bonus
    referrer_wallet.total_earned += bonus
    referral_record.status = 'credited'
    referral_record.credited_at = datetime.utcnow()
    referred_user.referral_bonus_credited = True
    history = PaymentHistory(
        user_id=referral_record.referrer_id,
        type='referral_bonus',
        amount=bonus,
        balance_before=balance_before,
        balance_after=referrer_wallet.balance,
        description=f"Referral bonus for inviting {referred_user.username}",
        reference_number=f"REF-{referred_user.id}"
    )
    db.session.add(history)


def process_pending_referral_bonuses():
    """
    Scheduled job: credit RM5 to referrers for verified users whose 24h fraud delay has passed.
    Run hourly. No-op while REFERRAL_ENABLED = False.
    """
    if not REFERRAL_ENABLED:
        return
    try:
        now = datetime.utcnow()
        due = Referral.query.filter(
            Referral.status == 'pending',
            Referral.credit_after <= now
        ).all()
        credited = 0
        for record in due:
            referred_user = User.query.get(record.referred_id)
            if not (referred_user and referred_user.is_verified
                    and referred_user.ic_number and referred_user.ic_number.strip()
                    and not referred_user.referral_bonus_credited):
                continue

            # Reject if the same IC is registered on any other account (duplicate identity)
            ic = referred_user.ic_number.strip()
            duplicate_ic = User.query.filter(
                User.ic_number == ic,
                User.id != referred_user.id
            ).first()
            if duplicate_ic:
                record.status = 'rejected'
                app.logger.warning(
                    f"Referral {record.id} rejected: IC {ic[:4]}**** already used by user {duplicate_ic.id}"
                )
                continue

            try:
                _apply_referral_credit(record, referred_user)
                credited += 1
            except Exception as e:
                app.logger.error(f"Referral credit error for referral {record.id}: {e}")
        if credited:
            db.session.commit()
            app.logger.info(f"Referral scheduler: credited {credited} bonus(es)")
    except Exception as e:
        db.session.rollback()
        app.logger.error(f"process_pending_referral_bonuses error: {e}")


def verify_email_token(token):
    """
    Verify email token and mark user as verified
    Returns (success, message, user) tuple
    """
    try:
        user = User.query.filter_by(email_verification_token=token).first()

        if not user:
            return False, "Invalid verification token", None

        # Check if token has expired (24 hours)
        if user.email_verification_expires and datetime.utcnow() > user.email_verification_expires:
            return False, "Verification link has expired. Please request a new one.", None

        # Check if already verified
        if user.is_verified:
            return True, "Email already verified", user

        # Mark user as verified
        user.is_verified = True
        user.email_verification_token = None
        user.email_verification_expires = None

        # Grant referral code now that the email is confirmed
        if not user.referral_code:
            user.referral_code = generate_referral_code()

        # Referral bonus is credited by the hourly scheduler only after the referred
        # user has both verified their email AND added their IC number (anti-spam).
        db.session.commit()

        app.logger.info(f"Email verified for user {user.username} ({user.email})")
        return True, "Email verified successfully", user
    except Exception as e:
        app.logger.error(f"Error verifying email token: {str(e)}")
        return False, f"Error verifying email: {str(e)}", None

