@app.route('/api/gigs/<int:gig_id>/applications', methods=['GET'])
def get_gig_applications(gig_id):
    """Get all applications for a gig (client only)"""
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    try:
        gig = Gig.query.get_or_404(gig_id)
        user_id = session['user_id']

        # Only client can view applications for their gig
        if gig.client_id != user_id:
            return jsonify({'error': 'Only the gig owner can view applications'}), 403

        # Get all applications with freelancer details
        applications = Application.query.filter_by(gig_id=gig_id).all()

        result = []
        for app in applications:
            freelancer = User.query.get(app.freelancer_id)
            result.append({
                'id': app.id,
                'gig_id': app.gig_id,
                'freelancer': {
                    'id': freelancer.id,
                    'username': freelancer.username,
                    'full_name': freelancer.full_name,
                    'rating': freelancer.rating,
                    'review_count': freelancer.review_count,
                    'completed_gigs': freelancer.completed_gigs,
                    'bio': freelancer.bio,
                    'location': freelancer.location,
                    'skills': json.loads(freelancer.skills) if freelancer.skills else [],
                    'is_verified': freelancer.is_verified,
                    'halal_verified': freelancer.halal_verified
                },
                'cover_letter': app.cover_letter,
                'proposed_price': app.proposed_price,
                'video_pitch': app.video_pitch,
                'status': app.status,
                'created_at': app.created_at.isoformat()
            })

        return jsonify({
            'gig_id': gig_id,
            'applications': result,
            'total_applications': len(result)
        }), 200

    except Exception as e:
        app.logger.error(f"Get applications error: {str(e)}")
        return jsonify({'error': 'Failed to retrieve applications'}), 500

@app.route('/api/applications/<int:application_id>/accept', methods=['POST'])
@verified_required
def accept_application(application_id):
    """Client accepts a freelancer's application"""
    try:
        application = Application.query.get_or_404(application_id)
        gig = Gig.query.get(application.gig_id)
        user_id = session['user_id']

        # Only client can accept applications
        if gig.client_id != user_id:
            return jsonify({'error': 'Only the gig owner can accept applications'}), 403

        # Check if gig is still open or in_progress (for multi-worker gigs)
        workers_needed = gig.workers_needed or 1
        if workers_needed > 1:
            # For multi-worker gigs, allow acceptance even when in_progress if slots available
            if gig.status not in ['open', 'in_progress']:
                return jsonify({'error': 'This gig is no longer accepting applications'}), 400
        else:
            # Single worker gig - must be open
            if gig.status != 'open':
                return jsonify({'error': 'This gig is no longer accepting applications'}), 400

        # Check if this freelancer is already assigned to this gig
        existing_assignment = GigWorker.query.filter_by(
            gig_id=gig.id,
            worker_id=application.freelancer_id
        ).first()
        if existing_assignment:
            return jsonify({'error': 'This freelancer is already assigned to this gig'}), 400

        # Count current workers assigned
        current_workers_count = GigWorker.query.filter_by(gig_id=gig.id, status='active').count()

        # Check if we have room for more workers
        if current_workers_count >= workers_needed:
            return jsonify({'error': 'All worker positions for this gig have been filled'}), 400

        # Accept this application
        application.status = 'accepted'

        # Calculate agreed amount for this worker
        agreed_amount = application.proposed_price if application.proposed_price else gig.budget_min

        # Create GigWorker entry for multi-worker tracking
        # Include specialized rate tracking for analytics and transparency
        gig_worker = GigWorker(
            gig_id=gig.id,
            worker_id=application.freelancer_id,
            application_id=application.id,
            agreed_amount=agreed_amount,
            status='active',
            specialized_rate_used=application.use_specialized_rate or False,
            specialization_id=application.specialization_id
        )
        db.session.add(gig_worker)

        # For backwards compatibility, also set the legacy freelancer_id if this is single worker gig
        # or if it's the first worker in a multi-worker gig
        if workers_needed == 1 or current_workers_count == 0:
            gig.freelancer_id = application.freelancer_id
            gig.agreed_amount = agreed_amount

        # Update gig status
        new_workers_count = current_workers_count + 1
        if new_workers_count >= workers_needed:
            # All positions filled - change to in_progress
            gig.status = 'in_progress'
            # Reject all remaining pending applications since all positions are filled
            other_applications = Application.query.filter(
                Application.gig_id == gig.id,
                Application.id != application_id,
                Application.status == 'pending'
            ).all()
            for other_app in other_applications:
                other_app.status = 'rejected'
        else:
            # Still need more workers - change to in_progress but keep accepting
            gig.status = 'in_progress'
            # Note: Other applications remain pending so client can accept more

        # Auto-create conversation between client and freelancer for THIS specific gig
        # Check if a conversation already exists for this specific gig
        existing_conv = Conversation.query.filter(
            ((Conversation.participant_1_id == user_id) & (Conversation.participant_2_id == application.freelancer_id)) |
            ((Conversation.participant_1_id == application.freelancer_id) & (Conversation.participant_2_id == user_id)),
            Conversation.gig_id == gig.id
        ).first()

        if not existing_conv:
            # Create a new conversation for this gig
            conversation = Conversation(
                participant_1_id=user_id,
                participant_2_id=application.freelancer_id,
                gig_id=gig.id
            )
            db.session.add(conversation)
            db.session.flush()  # Flush to get the conversation ID

            # Add a system message to notify about the acceptance
            system_message = Message(
                conversation_id=conversation.id,
                sender_id=user_id,
                content=f"Application accepted! Let's discuss the details of '{gig.title}'.",
                message_type='text'
            )
            conversation.last_message_at = datetime.utcnow()
            db.session.add(system_message)

        db.session.commit()

        # Send email and SMS notification to freelancer
        freelancer = User.query.get(application.freelancer_id)
        if freelancer:
            # Send email notification
            try:
                subject = "Application Accepted!"
                message = f"Congratulations! Your application for '{gig.title}' has been accepted by the client. You can now start working on the project."

                html_content = f"""
                <!DOCTYPE html>
                <html>
                <head>
                    <style>
                        body {{ font-family: Arial, sans-serif; line-height: 1.6; color: #333; }}
                        .container {{ max-width: 600px; margin: 0 auto; padding: 20px; }}
                        .header {{ background-color: #2ecc71; color: white; padding: 20px; text-align: center; }}
                        .content {{ padding: 20px; background-color: #f9f9f9; }}
                        .footer {{ padding: 20px; text-align: center; font-size: 12px; color: #777; }}
                    </style>
                </head>
                <body>
                    <div class="container">
                        <div class="header">
                            <h2>🎉 Application Accepted!</h2>
                        </div>
                        <div class="content">
                            <p>Hi {freelancer.full_name or freelancer.username},</p>
                            <p>Great news! Your application for <strong>"{gig.title}"</strong> has been accepted.</p>
                            <p><strong>Agreed Amount:</strong> RM {gig.agreed_amount if gig.agreed_amount else gig.budget_min}</p>
                            <p>You can now start working on the project. Check your dashboard for more details and to communicate with the client.</p>
                            <p>Good luck with your project!</p>
                        </div>
                        <div class="footer">
                            <p>GigHala - Your Trusted Syariah-Principled Gig Platform</p>
                        </div>
                    </div>
                </body>
                </html>
                """

                text_content = f"""
Application Accepted!

Hi {freelancer.full_name or freelancer.username},

Great news! Your application for "{gig.title}" has been accepted.

Agreed Amount: RM {gig.agreed_amount if gig.agreed_amount else gig.budget_min}

You can now start working on the project. Check your dashboard for more details.

---
GigHala - Your Trusted Syariah-Principled Gig Platform
                """.strip()

                success, msg, status_code, details = email_service.send_single_email(
                    to_email=freelancer.email,
                    to_name=freelancer.full_name or freelancer.username,
                    subject=subject,
                    html_content=html_content,
                    text_content=text_content
                )

                # Log email to database for archival
                log_email_to_database(
                    email_type='transactional',
                    subject=subject,
                    html_content=html_content,
                    text_content=text_content,
                    recipient_emails=freelancer.email,
                    recipient_user_id=freelancer.id,
                    success=success,
                    error_message=msg if not success else None,
                    brevo_message_ids=details.get('brevo_message_ids', []),
                    failed_recipients=details.get('failed_recipients', [])
                )

                app.logger.info(f"Sent application accepted email to freelancer {freelancer.id}")

            except Exception as e:
                app.logger.error(f"Failed to send application accepted email: {str(e)}")

            # Send SMS notification if phone is verified
            if freelancer.phone and freelancer.phone_verified:
                sms_message = f"GigHala: Congratulations! Your application for '{gig.title}' has been accepted. Check your dashboard to start working!"
                send_transaction_sms_notification(freelancer.phone, sms_message)

        # Build response message based on worker count
        workers_needed = gig.workers_needed or 1
        current_count = GigWorker.query.filter_by(gig_id=gig.id, status='active').count()
        remaining_slots = workers_needed - current_count

        if workers_needed > 1:
            if remaining_slots > 0:
                message = f'Application accepted successfully. {current_count}/{workers_needed} workers hired. {remaining_slots} more position(s) available.'
            else:
                message = f'Application accepted successfully. All {workers_needed} workers have been hired.'
        else:
            message = 'Application accepted successfully'

        return jsonify({
            'message': message,
            'gig': {
                'id': gig.id,
                'status': gig.status,
                'freelancer_id': gig.freelancer_id,
                'workers_needed': workers_needed,
                'workers_hired': current_count,
                'remaining_slots': remaining_slots
            }
        }), 200

    except Exception as e:
        db.session.rollback()
        app.logger.error(f"Accept application error: {str(e)}")
        return jsonify({'error': 'Failed to accept application'}), 500


@app.route('/api/gigs/<int:gig_id>/workers', methods=['GET'])
def get_gig_workers(gig_id):
    """Get all workers assigned to a gig (for multi-worker gigs)"""
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    try:
        gig = Gig.query.get_or_404(gig_id)
        user_id = session['user_id']

        # Only client or assigned workers can view the workers list
        is_client = gig.client_id == user_id
        is_worker = GigWorker.query.filter_by(gig_id=gig_id, worker_id=user_id).first() is not None

        if not is_client and not is_worker:
            return jsonify({'error': 'Access denied'}), 403

        # Get all workers for this gig
        gig_workers = GigWorker.query.filter_by(gig_id=gig_id).all()
        workers_needed = gig.workers_needed or 1
        workers_data = []

        for gw in gig_workers:
            worker = User.query.get(gw.worker_id)
            if worker:
                workers_data.append({
                    'id': gw.id,
                    'worker_id': gw.worker_id,
                    'worker_name': worker.full_name or worker.username,
                    'worker_username': worker.username,
                    'worker_avatar': f'/uploads/profile_photos/{worker.profile_photo}' if worker.profile_photo else None,
                    'worker_rating': worker.rating,
                    'worker_verified': worker.is_verified,
                    'agreed_amount': gw.agreed_amount,
                    'status': gw.status,
                    'work_submitted': gw.work_submitted,
                    'work_submission_date': gw.work_submission_date.isoformat() if gw.work_submission_date else None,
                    'assigned_at': gw.assigned_at.isoformat() if gw.assigned_at else None,
                    'completed_at': gw.completed_at.isoformat() if gw.completed_at else None
                })

        return jsonify({
            'gig_id': gig_id,
            'gig_title': gig.title,
            'workers_needed': workers_needed,
            'workers_hired': len(gig_workers),
            'remaining_slots': max(0, workers_needed - len(gig_workers)),
            'is_multi_worker': workers_needed > 1,
            'workers': workers_data
        }), 200

    except Exception as e:
        app.logger.error(f"Get gig workers error: {str(e)}")
        return jsonify({'error': 'Failed to retrieve workers'}), 500


