@app.route('/api/profile', methods=['PUT'])
def update_profile():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    try:
        user = User.query.get(session['user_id'])
        if not user:
            return jsonify({'error': 'User not found'}), 404

        data = request.json
        if not data:
            return jsonify({'error': 'No data provided'}), 400

        # Sanitize and validate inputs
        if 'full_name' in data:
            user.full_name = sanitize_input(data['full_name'], max_length=120)

        if 'phone' in data:
            is_valid, message = validate_phone(data['phone'])
            if not is_valid:
                return jsonify({'error': message}), 400
            user.phone = data['phone']

        if 'location' in data:
            user.location = sanitize_input(data['location'], max_length=100)

        if 'bio' in data:
            user.bio = sanitize_input(data['bio'], max_length=2000)

        if 'skills' in data:
            skills = data['skills']
            if not isinstance(skills, list):
                return jsonify({'error': 'Skills must be an array'}), 400
            # Limit to 20 skills, each max 50 chars
            skills = [sanitize_input(str(skill), max_length=50) for skill in skills[:20]]
            user.skills = json.dumps(skills)

        if 'language' in data:
            if data['language'] not in ['ms', 'en']:
                return jsonify({'error': 'Invalid language. Choose "ms" or "en"'}), 400
            user.language = data['language']

        if 'user_type' in data:
            if data['user_type'] not in ['freelancer', 'client', 'both']:
                return jsonify({'error': 'Invalid user type'}), 400
            user.user_type = data['user_type']

        if 'portfolio_url' in data:
            user.portfolio_url = sanitize_input(data['portfolio_url'], max_length=500)

        if 'ic_number' in data:
            ic = sanitize_input(data['ic_number'], max_length=20)
            is_valid, msg = validate_ic_number(ic)
            if not is_valid:
                return jsonify({'error': msg}), 400
            user.ic_number = ic

        if 'socso_membership_number' in data:
            user.socso_membership_number = sanitize_input(data['socso_membership_number'], max_length=20)

        if 'socso_consent' in data:
            user.socso_consent = bool(data['socso_consent'])
            if user.socso_consent and not user.socso_consent_date:
                user.socso_consent_date = datetime.utcnow()

        db.session.commit()

        return jsonify({'message': 'Profile updated successfully'})
    except Exception as e:
        db.session.rollback()
        app.logger.error(f"Update profile error: {str(e)}")
        return jsonify({'error': 'Failed to update profile. Please try again.'}), 500

@app.route('/api/language', methods=['POST'])
def switch_language():
    """Switch user's language preference"""
    try:
        data = request.json
        language = data.get('language', 'ms')

        # Validate language
        if language not in ['ms', 'en']:
            return jsonify({'error': 'Invalid language. Choose "ms" or "en"'}), 400

        # Update user's language if logged in
        if 'user_id' in session:
            user = User.query.get(session['user_id'])
            if user:
                user.language = language
                db.session.commit()
        else:
            # Store in session for non-logged in users
            session['language'] = language

        return jsonify({
            'message': 'Language updated successfully',
            'language': language
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f"Language switch error: {str(e)}")
        return jsonify({'error': 'Failed to update language'}), 500

@app.route('/api/admin/db-diagnostics', methods=['GET'])
def db_diagnostics():
    """Diagnostic endpoint: shows DB user, table ownership, and privilege status.

    Only accessible to logged-in admin users (is_admin=True).
    Hit this URL to find out exactly what SQL to run as superuser if
    worker_specialization still shows 'permission denied'.
    """
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401
    user = User.query.get(session['user_id'])
    if not user or not getattr(user, 'is_admin', False):
        return jsonify({'error': 'Forbidden'}), 403

    result = {}
    try:
        from sqlalchemy import text as _diag_text
        with db.engine.connect() as _conn:
            # Current connected role
            row = _conn.execute(_diag_text('SELECT current_user, session_user')).fetchone()
            result['current_user'] = row[0] if row else 'unknown'
            result['session_user'] = row[1] if row else 'unknown'

            # Table ownership
            for tbl in ('worker_specialization', 'worker_rate_audit'):
                row = _conn.execute(_diag_text(
                    f"SELECT tableowner, schemaname FROM pg_tables WHERE tablename = '{tbl}'"
                )).fetchone()
                result[f'{tbl}_owner'] = row[0] if row else 'TABLE NOT FOUND'
                result[f'{tbl}_schema'] = row[1] if row else 'N/A'

            # Privilege check
            for tbl in ('worker_specialization', 'worker_rate_audit'):
                can_select = False
                try:
                    _conn.execute(_diag_text(f'SELECT 1 FROM {tbl} LIMIT 1'))
                    can_select = True
                except Exception:
                    _conn.rollback()
                result[f'{tbl}_can_select'] = can_select

            # Role memberships
            try:
                rows = _conn.execute(_diag_text(
                    "SELECT r.rolname FROM pg_roles r "
                    "JOIN pg_auth_members m ON m.roleid = r.oid "
                    "JOIN pg_roles u ON u.oid = m.member "
                    "WHERE u.rolname = current_user"
                )).fetchall()
                result['role_memberships'] = [r[0] for r in rows]
            except Exception:
                result['role_memberships'] = 'unavailable'

        result['fix_sql'] = (
            f"ALTER TABLE worker_specialization OWNER TO \"{result['current_user']}\";\n"
            f"ALTER TABLE worker_rate_audit OWNER TO \"{result['current_user']}\";"
        )
    except Exception as e:
        result['error'] = str(e)

    return jsonify(result)


