@app.route('/api/workers/search', methods=['GET'])
def search_specialized_workers():
    """Search for workers by specialization, skills, and rate range.

    Query params:
    - q: Search query (name, username, skills)
    - category_id: Filter by category
    - skill: Filter by specific skill
    - min_rate: Minimum hourly rate
    - max_rate: Maximum hourly rate
    - min_fixed_rate: Minimum fixed rate
    - max_fixed_rate: Maximum fixed rate
    - has_rates: Boolean, only show workers with defined rates
    - location: Filter by location
    - min_rating: Minimum rating (1-5)
    - verified_only: Boolean, only verified workers
    - page: Page number (default 1)
    - limit: Number of results per page (default 20, max 50)
    """
    try:
        search_query = request.args.get('q', '').strip()
        category_id = request.args.get('category_id', type=int)
        category_slug = request.args.get('category_slug', '').strip()
        skill = request.args.get('skill', '').strip()
        min_rate = request.args.get('min_rate', type=float)
        max_rate = request.args.get('max_rate', type=float)
        min_fixed_rate = request.args.get('min_fixed_rate', type=float)
        max_fixed_rate = request.args.get('max_fixed_rate', type=float)
        has_rates = request.args.get('has_rates', 'false').lower() == 'true'
        location = request.args.get('location', '').strip()
        min_rating = request.args.get('min_rating', type=float)
        verified_only = request.args.get('verified_only', 'false').lower() == 'true'
        page = max(1, request.args.get('page', 1, type=int))
        limit = min(request.args.get('limit', 20, type=int), 50)
        offset = (page - 1) * limit

        # Build query - join User and WorkerSpecialization
        query = db.session.query(User, WorkerSpecialization).join(
            WorkerSpecialization, User.id == WorkerSpecialization.user_id
        ).filter(
            User.user_type.in_(['freelancer', 'both'])
        )

        # Search by name/username
        if search_query:
            search_pattern = f'%{search_query}%'
            query = query.filter(
                db.or_(
                    User.full_name.ilike(search_pattern),
                    User.username.ilike(search_pattern),
                    WorkerSpecialization.skills.ilike(search_pattern),
                    WorkerSpecialization.specialization_title.ilike(search_pattern)
                )
            )

        # Filter by category
        if category_id:
            query = query.filter(WorkerSpecialization.category_id == category_id)
        elif category_slug:
            # Resolve slug to category IDs — match exact slug and sub-categories containing the slug
            matched_cats = Category.query.filter(
                db.or_(
                    Category.slug == category_slug,
                    Category.slug.ilike(f'%{category_slug}%')
                )
            ).all()
            if matched_cats:
                matched_ids = [c.id for c in matched_cats]
                query = query.filter(WorkerSpecialization.category_id.in_(matched_ids))

        # Filter by skill (search within JSON skills array)
        if skill:
            skill_pattern = f'%{skill}%'
            query = query.filter(WorkerSpecialization.skills.ilike(skill_pattern))

        # Filter by rates
        if has_rates:
            query = query.filter(
                db.or_(
                    WorkerSpecialization.base_hourly_rate.isnot(None),
                    WorkerSpecialization.base_fixed_rate.isnot(None)
                )
            )

        if min_rate is not None:
            query = query.filter(WorkerSpecialization.base_hourly_rate >= min_rate)

        if max_rate is not None:
            query = query.filter(WorkerSpecialization.base_hourly_rate <= max_rate)

        if min_fixed_rate is not None:
            query = query.filter(WorkerSpecialization.base_fixed_rate >= min_fixed_rate)

        if max_fixed_rate is not None:
            query = query.filter(WorkerSpecialization.base_fixed_rate <= max_fixed_rate)

        # Filter by location
        if location:
            location_pattern = f'%{location}%'
            query = query.filter(User.location.ilike(location_pattern))

        # Filter by minimum rating
        if min_rating is not None:
            query = query.filter(User.rating >= min_rating)

        # Filter verified only
        if verified_only:
            query = query.filter(User.is_verified == True)

        # Get total count before pagination
        total_count = query.count()

        # Order by rating (descending), then by completed gigs
        query = query.order_by(User.rating.desc().nullslast(), User.completed_gigs.desc().nullslast())

        # Apply pagination
        results_raw = query.offset(offset).limit(limit).all()

        # Group specializations by worker
        workers_dict = {}
        for user, spec in results_raw:
            if user.id not in workers_dict:
                bio_text = user.bio or ''
                workers_dict[user.id] = {
                    'id': user.id,
                    'worker_id': user.id,
                    'username': user.username,
                    'name': user.full_name or user.username,
                    'full_name': user.full_name,
                    'bio': bio_text[:200] + '...' if len(bio_text) > 200 else bio_text,
                    'full_bio': bio_text,
                    'location': user.location,
                    'profile_picture': f'/uploads/profile_photos/{user.profile_photo}' if user.profile_photo else None,
                    'rating': float(user.rating or 0),
                    'review_count': user.review_count or 0,
                    'total_reviews': user.review_count or 0,
                    'completed_gigs': user.completed_gigs or 0,
                    'is_verified': user.is_verified,
                    'halal_verified': user.halal_verified,
                    'response_rate': None,
                    'specializations': [],
                    'min_hourly_rate': None,
                    'min_fixed_rate': None,
                }
            workers_dict[user.id]['specializations'].append(spec.to_public_dict())
            # Track minimum rates across all specializations
            if spec.base_hourly_rate:
                current_min = workers_dict[user.id]['min_hourly_rate']
                if current_min is None or spec.base_hourly_rate < current_min:
                    workers_dict[user.id]['min_hourly_rate'] = float(spec.base_hourly_rate)
            if spec.base_fixed_rate:
                current_min = workers_dict[user.id]['min_fixed_rate']
                if current_min is None or spec.base_fixed_rate < current_min:
                    workers_dict[user.id]['min_fixed_rate'] = float(spec.base_fixed_rate)

        workers = list(workers_dict.values())

        return jsonify({
            'workers': workers,
            'count': len(workers),
            'total': total_count,
            'page': page,
            'pages': (total_count + limit - 1) // limit,
            'limit': limit
        })
    except Exception as e:
        app.logger.error(f"Search specialized workers error: {str(e)}")
        return jsonify({'error': 'Failed to search workers'}), 500


@app.route('/api/skills/browse', methods=['GET'])
def browse_skills_api():
    """Browse individual worker skills/services with pricing - Fiverr-style.

    Returns one card per WorkerSpecialization (skill offering), not per worker.

    Query params:
    - q: Search query (skill name, title, worker name)
    - category_id: Filter by category
    - min_price: Minimum price (checks both hourly and fixed rates)
    - max_price: Maximum price
    - sort: Sorting option (price_low, price_high, rating, newest, popular)
    - verified_only: Boolean, only verified workers
    - page: Page number (default 1)
    - limit: Results per page (default 24, max 60)
    """
    try:
        import json as json_lib

        search_query = request.args.get('q', '').strip()
        category_id = request.args.get('category_id', type=int)
        min_price = request.args.get('min_price', type=float)
        max_price = request.args.get('max_price', type=float)
        sort = request.args.get('sort', 'popular').strip()
        verified_only = request.args.get('verified_only', 'false').lower() == 'true'
        page = max(1, request.args.get('page', 1, type=int))
        limit = min(request.args.get('limit', 24, type=int), 60)
        offset = (page - 1) * limit

        # Query WorkerSpecialization joined with User and Category
        query = db.session.query(WorkerSpecialization, User, Category).join(
            User, WorkerSpecialization.user_id == User.id
        ).join(
            Category, WorkerSpecialization.category_id == Category.id
        ).filter(
            User.user_type.in_(['freelancer', 'both'])
        )

        # Only show skills that have at least one rate defined
        query = query.filter(
            db.or_(
                WorkerSpecialization.base_hourly_rate.isnot(None),
                WorkerSpecialization.base_fixed_rate.isnot(None)
            )
        )

        # Search filter
        if search_query:
            search_pattern = f'%{search_query}%'
            query = query.filter(
                db.or_(
                    WorkerSpecialization.specialization_title.ilike(search_pattern),
                    WorkerSpecialization.skills.ilike(search_pattern),
                    Category.name.ilike(search_pattern),
                    User.full_name.ilike(search_pattern),
                    User.username.ilike(search_pattern)
                )
            )

        # Category filter
        if category_id:
            query = query.filter(WorkerSpecialization.category_id == category_id)

        # Price filter (check both hourly and fixed rates)
        if min_price is not None:
            query = query.filter(
                db.or_(
                    WorkerSpecialization.base_hourly_rate >= min_price,
                    WorkerSpecialization.base_fixed_rate >= min_price
                )
            )
        if max_price is not None:
            query = query.filter(
                db.or_(
                    db.and_(
                        WorkerSpecialization.base_hourly_rate.isnot(None),
                        WorkerSpecialization.base_hourly_rate <= max_price
                    ),
                    db.and_(
                        WorkerSpecialization.base_fixed_rate.isnot(None),
                        WorkerSpecialization.base_fixed_rate <= max_price
                    )
                )
            )

        # Verified filter
        if verified_only:
            query = query.filter(User.is_verified == True)

        # Get total count
        total_count = query.count()

        # Sorting
        if sort == 'price_low':
            query = query.order_by(
                db.func.coalesce(WorkerSpecialization.base_fixed_rate, WorkerSpecialization.base_hourly_rate).asc()
            )
        elif sort == 'price_high':
            query = query.order_by(
                db.func.coalesce(WorkerSpecialization.base_fixed_rate, WorkerSpecialization.base_hourly_rate).desc()
            )
        elif sort == 'rating':
            query = query.order_by(User.rating.desc().nullslast())
        elif sort == 'newest':
            query = query.order_by(WorkerSpecialization.created_at.desc())
        else:  # popular (default)
            query = query.order_by(User.completed_gigs.desc().nullslast(), User.rating.desc().nullslast())

        # Pagination
        results = query.offset(offset).limit(limit).all()

        # Build response - one entry per skill/service
        services = []
        for spec, user, category in results:
            skills_list = json_lib.loads(spec.skills) if spec.skills else []

            # Determine the display price
            starting_price = None
            price_type = None
            if spec.base_fixed_rate:
                starting_price = spec.base_fixed_rate
                price_type = 'fixed'
            elif spec.base_hourly_rate:
                starting_price = spec.base_hourly_rate
                price_type = 'hourly'

            services.append({
                'id': spec.id,
                'title': spec.specialization_title or f"{get_category_display_name(category.slug, 'ms')} Servis",
                'category_name': get_category_display_name(category.slug, 'ms'),
                'category_id': category.id,
                'category_icon': category.icon,
                'skills': skills_list[:5],
                'starting_price': starting_price,
                'price_type': price_type,
                'hourly_rate': spec.base_hourly_rate,
                'fixed_rate': spec.base_fixed_rate,
                'has_premium': (spec.premium_multiplier or 1.0) > 1.0,
                'worker': {
                    'id': user.id,
                    'username': user.username,
                    'name': user.full_name or user.username,
                    'location': user.location,
                    'rating': user.rating or 0,
                    'review_count': user.review_count or 0,
                    'completed_gigs': user.completed_gigs or 0,
                    'is_verified': user.is_verified,
                    'halal_verified': user.halal_verified,
                    'profile_photo': f'/uploads/profile_photos/{user.profile_photo}' if user.profile_photo else None,
                }
            })

        return jsonify({
            'services': services,
            'total': total_count,
            'page': page,
            'pages': (total_count + limit - 1) // limit if total_count > 0 else 0,
            'limit': limit
        })
    except Exception as e:
        app.logger.error(f"Browse skills API error: {str(e)}")
        return jsonify({'error': 'Failed to browse services'}), 500


@app.route('/api/worker-updates', methods=['GET'])
@login_required
def get_worker_updates():
    """Return workers who recently updated their skills or pricing.

    Query params:
    - days: Look-back window in days (default 30)
    - category_id: Filter by category
    - page: Page number (default 1)
    - limit: Results per page (default 24, max 60)
    """
    try:
        import json as json_lib

        days = max(1, request.args.get('days', 30, type=int))
        category_id = request.args.get('category_id', type=int)
        page = max(1, request.args.get('page', 1, type=int))
        limit = min(request.args.get('limit', 24, type=int), 60)
        offset = (page - 1) * limit

        since = datetime.utcnow() - timedelta(days=days)

        query = db.session.query(WorkerSpecialization, User, Category).join(
            User, WorkerSpecialization.user_id == User.id
        ).join(
            Category, WorkerSpecialization.category_id == Category.id
        ).filter(
            User.user_type.in_(['freelancer', 'both']),
            WorkerSpecialization.updated_at >= since,
            db.or_(
                WorkerSpecialization.base_hourly_rate.isnot(None),
                WorkerSpecialization.base_fixed_rate.isnot(None)
            )
        )

        if category_id:
            query = query.filter(WorkerSpecialization.category_id == category_id)

        total_count = query.count()
        results = query.order_by(WorkerSpecialization.updated_at.desc()).offset(offset).limit(limit).all()

        updates = []
        for spec, user, category in results:
            skills_list = json_lib.loads(spec.skills) if spec.skills else []
            starting_price = spec.base_fixed_rate or spec.base_hourly_rate
            price_type = 'fixed' if spec.base_fixed_rate else 'hourly'

            updates.append({
                'id': spec.id,
                'title': spec.specialization_title or f"{get_category_display_name(category.slug, 'ms')} Servis",
                'category_name': get_category_display_name(category.slug, 'ms'),
                'category_id': category.id,
                'category_slug': category.slug,
                'category_icon': category.icon,
                'skills': skills_list[:5],
                'starting_price': starting_price,
                'price_type': price_type,
                'hourly_rate': spec.base_hourly_rate,
                'fixed_rate': spec.base_fixed_rate,
                'has_premium': (spec.premium_multiplier or 1.0) > 1.0,
                'updated_at': spec.updated_at.isoformat() if spec.updated_at else None,
                'worker': {
                    'id': user.id,
                    'username': user.username,
                    'name': user.full_name or user.username,
                    'location': user.location,
                    'rating': user.rating or 0,
                    'review_count': user.review_count or 0,
                    'completed_gigs': user.completed_gigs or 0,
                    'is_verified': user.is_verified,
                    'halal_verified': user.halal_verified,
                    'profile_photo': f'/uploads/profile_photos/{user.profile_photo}' if user.profile_photo else None,
                }
            })

        return jsonify({
            'updates': updates,
            'total': total_count,
            'page': page,
            'pages': (total_count + limit - 1) // limit if total_count > 0 else 0,
            'limit': limit,
            'days': days
        })
    except Exception as e:
        app.logger.error(f"Worker updates API error: {str(e)}")
        return jsonify({'error': 'Failed to fetch worker updates'}), 500


