def calculate_next_batch_release_time():
    """Calculate the next batch release time (8am or 4pm)

    Returns:
        tuple: (scheduled_release_time as datetime, batch identifier as string)
    """
    from pytz import timezone

    # Use Malaysia timezone (MYT = UTC+8)
    myt = timezone('Asia/Kuala_Lumpur')
    now = datetime.now(myt)

    # Define batch times
    batch_8am = now.replace(hour=8, minute=0, second=0, microsecond=0)
    batch_4pm = now.replace(hour=16, minute=0, second=0, microsecond=0)

    # Determine next batch
    if now < batch_8am:
        # Before 8am - assign to today's 8am batch
        next_batch = batch_8am
    elif now < batch_4pm:
        # Between 8am and 4pm - assign to today's 4pm batch
        next_batch = batch_4pm
    else:
        # After 4pm - assign to tomorrow's 8am batch
        next_batch = (now + timedelta(days=1)).replace(hour=8, minute=0, second=0, microsecond=0)

    # Create batch identifier (e.g., "2026-01-12-08:00" or "2026-01-12-16:00")
    batch_id = next_batch.strftime('%Y-%m-%d-%H:%M')

    # Convert to UTC for database storage
    next_batch_utc = next_batch.astimezone(timezone('UTC')).replace(tzinfo=None)

    return next_batch_utc, batch_id

@app.route('/api/billing/payouts', methods=['POST'])
@verified_required
def request_payout():
    """Request a payout withdrawal from wallet balance (NO SOCSO deduction on payout - SOCSO deducted on escrow release)"""
    try:
        user_id = session['user_id']
        data = request.get_json()

        amount = data.get('amount')
        payment_method = data.get('payment_method')
        account_number = data.get('account_number')
        account_name = data.get('account_name')
        bank_name = data.get('bank_name')

        # Validate
        if not all([amount, payment_method, account_number, account_name]):
            return jsonify({'error': 'Missing required fields'}), 400

        try:
            amount = float(amount)
        except (TypeError, ValueError):
            return jsonify({'error': 'Invalid amount format'}), 400

        if amount <= 0:
            return jsonify({'error': 'Invalid amount'}), 400

        # Get user
        user = User.query.get(user_id)
        if not user:
            return jsonify({'error': 'User not found'}), 404

        # Check wallet balance
        wallet = Wallet.query.filter_by(user_id=user_id).first()
        if not wallet or wallet.balance < amount:
            return jsonify({'error': 'Insufficient balance'}), 400

        # ALLOW multiple pending payouts - removing restriction if it existed
        # Based on user feedback "stuck with one payout", I'll ensure we don't block additional requests
        app.logger.info(f"User {user_id} requesting payout of {amount}. Current balance: {wallet.balance}")
        
        # Calculate fee (2% platform fee only - NO SOCSO deduction here)
        # SOCSO is deducted only when client releases escrow, not on payout withdrawal
        fee = round(amount * 0.02, 2)

        # Net amount after fee deduction only (SOCSO already deducted at escrow release)
        net_amount = round(amount - fee, 2)

        # Generate payout number
        import random
        payout_number = f"PO-{datetime.utcnow().strftime('%Y%m%d')}-{random.randint(10000, 99999)}"

        # Calculate next batch release time for manual payouts (8am or 4pm)
        scheduled_release_time, release_batch = calculate_next_batch_release_time()

        # Create payout request
        payout = Payout(
            payout_number=payout_number,
            freelancer_id=user_id,
            amount=amount,
            fee=fee,
            socso_amount=0.0,  # NO SOCSO deduction on payout - already deducted at escrow release
            net_amount=net_amount,
            payment_method=payment_method,
            account_number=account_number,
            account_name=account_name,
            bank_name=bank_name,
            status='pending',
            scheduled_release_time=scheduled_release_time,
            release_batch=release_batch
        )

        db.session.add(payout)
        db.session.flush()  # Get payout ID

        # Hold the balance
        wallet.balance -= amount
        wallet.held_balance += amount

        # Create payment history for hold
        history = PaymentHistory(
            user_id=user_id,
            payout_id=payout.id,
            type='hold',
            amount=amount,
            socso_amount=0.0,  # NO SOCSO on payout
            balance_before=wallet.balance + amount,
            balance_after=wallet.balance,
            description=f'Payout request {payout_number} (SOCSO already deducted at escrow release)'
        )

        db.session.add(history)
        db.session.commit()

        # Log financial operation
        security_logger.log_financial(
            event_type='payout_requested',
            action=f'Payout request submitted by {user.username}',
            amount=amount,
            resource_type='payout',
            resource_id=payout_number,
            details={
                'payout_number': payout_number,
                'amount': amount,
                'fee': fee,
                'net_amount': net_amount,
                'payment_method': payment_method,
                'wallet_balance_before': wallet.balance + amount,
                'wallet_balance_after': wallet.balance
            }
        )

        # Send withdrawal request confirmation email
        if user.email:
            try:
                html_content = render_template('email_withdrawal_confirmation.html',
                    recipient_name=user.full_name or user.username,
                    withdrawal_status="Processing",
                    status_message="Your withdrawal request has been received",
                    main_message="We have received your withdrawal request and it is currently being processed.",
                    withdrawal_amount=f"{amount:.2f}",
                    transaction_id=payout_number,
                    request_date=datetime.utcnow().strftime('%d %B %Y, %H:%M'),
                    processing_date=None,
                    completion_date=None,
                    bank_name=bank_name,
                    bank_account_number=account_number,
                    account_holder_name=account_name,
                    withdrawal_fee=f"{fee:.2f}",
                    requested_amount=f"{amount:.2f}",
                    estimated_completion=(datetime.utcnow() + timedelta(days=3)).strftime('%d %B %Y'),
                    wallet_url=request.host_url.rstrip('/') + '/wallet',
                    transaction_url=request.host_url.rstrip('/') + '/payments',
                    support_url=request.host_url.rstrip('/') + '/support',
                    support_contact='support@gighala.my',
                    settings_url=request.host_url.rstrip('/') + '/settings',
                    terms_url=request.host_url.rstrip('/') + '/terms'
                )

                subject = f"Withdrawal Request Received - {payout_number}"
                success, msg, status_code, details = email_service.send_single_email(
                    to_email=user.email,
                    to_name=user.full_name or user.username,
                    subject=subject,
                    html_content=html_content
                )

                # Log email to database for archival
                log_email_to_database(
                    email_type='transactional',
                    subject=subject,
                    html_content=html_content,
                    text_content=None,
                    recipient_emails=user.email,
                    recipient_user_id=user.id,
                    success=success,
                    error_message=msg if not success else None,
                    brevo_message_ids=details.get('brevo_message_ids', []),
                    failed_recipients=details.get('failed_recipients', [])
                )

                app.logger.info(f"Sent withdrawal request email to user {user_id}")
            except Exception as e:
                app.logger.error(f"Failed to send withdrawal request email: {str(e)}")

        # Send SMS notification for large withdrawals (>= RM500)
        if user.phone and (amount >= 500 or user.phone_verified):
            try:
                sms_message = f"GigHala: Withdrawal request of MYR {amount:.2f} received. Ref: {payout_number}. Processing time: 1-3 business days."
                send_transaction_sms_notification(user.phone, sms_message)
                app.logger.info(f"Sent withdrawal request SMS to user {user_id} (amount: MYR {amount:.2f})")
            except Exception as e:
                app.logger.error(f"Failed to send withdrawal request SMS: {str(e)}")

        return jsonify({
            'message': 'Payout request submitted successfully',
            'payout_number': payout_number,
            'status': 'pending',
            'amount': amount,
            'fee': fee,
            'socso_amount': 0.0,
            'net_amount': net_amount,
            'breakdown': {
                'gross_amount': amount,
                'platform_fee': fee,
                'socso_contribution': 0.0,
                'final_payout': net_amount
            }
        }), 201
    except Exception as e:
        db.session.rollback()
        app.logger.error(f"Request payout error: {str(e)}")
        return jsonify({'error': 'Failed to request payout'}), 500

