@app.route('/support/message')
@login_required
def message_support():
    """Start a conversation with support"""
    try:
        user_id = session['user_id']
        
        support_user = User.query.filter_by(username='support').first()
        if not support_user:
            support_user = User(
                username='support',
                email='support@gighala.local',
                password_hash='disabled',
                full_name='GigHala Support',
                is_verified=True
            )
            db.session.add(support_user)
            db.session.flush()
        
        existing = Conversation.query.filter(
            ((Conversation.participant_1_id == user_id) & (Conversation.participant_2_id == support_user.id)) |
            ((Conversation.participant_1_id == support_user.id) & (Conversation.participant_2_id == user_id))
        ).first()
        
        if existing:
            conv_id = existing.id
        else:
            conv = Conversation(
                participant_1_id=user_id,
                participant_2_id=support_user.id
            )
            db.session.add(conv)
            db.session.commit()
            conv_id = conv.id
        
        db.session.commit()
        return redirect(f'/messages/{conv_id}')
    except Exception as e:
        app.logger.error(f"Error starting support conversation: {str(e)}")
        return redirect('/messages')

@app.route('/messages')
@page_login_required
def messages():
    """View all conversations"""
    user_id = session['user_id']
    user = User.query.get(user_id)
    
    conversations = Conversation.query.filter(
        ((Conversation.participant_1_id == user_id) & (Conversation.is_archived_by_1 == False)) |
        ((Conversation.participant_2_id == user_id) & (Conversation.is_archived_by_2 == False))
    ).order_by(Conversation.last_message_at.desc()).all()
    
    conversation_list = []
    for conv in conversations:
        other_user_id = conv.participant_2_id if conv.participant_1_id == user_id else conv.participant_1_id
        other_user = User.query.get(other_user_id)
        last_message = Message.query.filter_by(conversation_id=conv.id).order_by(Message.created_at.desc()).first()
        unread_count = Message.query.filter_by(conversation_id=conv.id, is_read=False).filter(Message.sender_id != user_id).count()
        gig = Gig.query.get(conv.gig_id) if conv.gig_id else None

        # Determine message type for color coding
        message_type = 'dm'  # Default to direct message
        if other_user and other_user.admin_role:
            message_type = 'support'  # Support/Admin message
        elif gig:
            message_type = 'gig'  # Gig-related message

        conversation_list.append({
            'id': conv.id,
            'other_user': other_user,
            'last_message': last_message,
            'unread_count': unread_count,
            'gig': gig,
            'last_message_at': conv.last_message_at,
            'message_type': message_type
        })
    
    return render_template('messages.html', user=user, conversations=conversation_list, active_page='messages', lang=get_user_language(), t=t)

@app.route('/messages/<int:conversation_id>')
@page_login_required
def view_conversation(conversation_id):
    """View a specific conversation"""
    user_id = session['user_id']
    user = User.query.get(user_id)
    
    conv = Conversation.query.get_or_404(conversation_id)
    if conv.participant_1_id != user_id and conv.participant_2_id != user_id:
        return redirect('/messages')
    
    other_user_id = conv.participant_2_id if conv.participant_1_id == user_id else conv.participant_1_id
    other_user = User.query.get(other_user_id)
    
    messages_list = Message.query.filter_by(conversation_id=conversation_id).order_by(Message.created_at.asc()).all()
    
    Message.query.filter_by(conversation_id=conversation_id, is_read=False).filter(Message.sender_id != user_id).update({'is_read': True, 'read_at': datetime.utcnow()})
    db.session.commit()
    
    gig = Gig.query.get(conv.gig_id) if conv.gig_id else None
    
    return render_template('conversation.html', user=user, conversation=conv, other_user=other_user, messages=messages_list, gig=gig, active_page='messages', lang=get_user_language(), t=t)

MESSAGE_IMAGE_FOLDER = os.path.join(UPLOAD_FOLDER, 'messages')
os.makedirs(MESSAGE_IMAGE_FOLDER, exist_ok=True)

SUPPORT_ATTACHMENT_FOLDER = os.path.join(UPLOAD_FOLDER, 'support_attachments')
os.makedirs(SUPPORT_ATTACHMENT_FOLDER, exist_ok=True)

ALLOWED_IMAGE_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'webp'}
ALLOWED_FILE_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'webp', 'pdf', 'doc', 'docx'}

@app.route('/uploads/messages/<filename>')
@login_required
def serve_message_image(filename):
    """Serve message images (authenticated users only)"""
    safe_path = os.path.abspath(os.path.join(MESSAGE_IMAGE_FOLDER, filename))
    if not safe_path.startswith(os.path.abspath(MESSAGE_IMAGE_FOLDER)):
        return jsonify({'error': 'Forbidden'}), 403
    return send_from_directory(MESSAGE_IMAGE_FOLDER, filename)

@app.route('/api/messages/upload-image', methods=['POST'])
@login_required
def upload_message_image():
    """Upload an image to be attached to a chat message"""
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
        file = request.files['image']
        if not file or not file.filename:
            return jsonify({'error': 'No image provided'}), 400
        ext = file.filename.rsplit('.', 1)[-1].lower() if '.' in file.filename else ''
        if ext not in ALLOWED_IMAGE_EXTENSIONS:
            return jsonify({'error': 'File type not allowed'}), 400
        file.seek(0, 2)
        size = file.tell()
        file.seek(0)
        if size > MAX_FILE_SIZE:
            return jsonify({'error': 'Image exceeds 5 MB limit'}), 400
        filename = f"{uuid.uuid4().hex}.{ext}"
        save_path = os.path.join(MESSAGE_IMAGE_FOLDER, filename)
        if not os.path.abspath(save_path).startswith(os.path.abspath(MESSAGE_IMAGE_FOLDER)):
            return jsonify({'error': 'Invalid path'}), 400
        file.save(save_path)
        return jsonify({'url': f'/uploads/messages/{filename}'}), 200
    except Exception as e:
        app.logger.error(f"Message image upload error: {str(e)}")
        return jsonify({'error': 'Upload failed'}), 500


@app.route('/api/messages/upload-file', methods=['POST'])
@login_required
def upload_message_file():
    """Upload any allowed file (image or document) to be attached to a chat message"""
    try:
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400
        file = request.files['file']
        if not file or not file.filename:
            return jsonify({'error': 'No file provided'}), 400
        original_name = file.filename
        ext = original_name.rsplit('.', 1)[-1].lower() if '.' in original_name else ''
        if ext not in ALLOWED_FILE_EXTENSIONS:
            return jsonify({'error': 'File type not allowed. Allowed: images, PDF, DOC, DOCX'}), 400
        file.seek(0, 2)
        size = file.tell()
        file.seek(0)
        if size > MAX_FILE_SIZE:
            return jsonify({'error': 'File exceeds 5 MB limit'}), 400
        filename = f"{uuid.uuid4().hex}.{ext}"
        save_path = os.path.join(MESSAGE_IMAGE_FOLDER, filename)
        if not os.path.abspath(save_path).startswith(os.path.abspath(MESSAGE_IMAGE_FOLDER)):
            return jsonify({'error': 'Invalid path'}), 400
        file.save(save_path)
        is_image = ext in ALLOWED_IMAGE_EXTENSIONS
        return jsonify({
            'url': f'/uploads/messages/{filename}',
            'filename': original_name,
            'message_type': 'image' if is_image else 'file'
        }), 200
    except Exception as e:
        app.logger.error(f"Message file upload error: {str(e)}")
        return jsonify({'error': 'Upload failed'}), 500


