@app.route('/api/verification/submit', methods=['POST'])
@login_required
def submit_verification():
    """Submit identity verification"""
    try:
        user_id = session['user_id']
        
        existing = IdentityVerification.query.filter_by(user_id=user_id, status='pending').first()
        if existing:
            return jsonify({'error': 'You already have a pending verification'}), 400
        
        if request.form.get('verification_consent') != 'on':
            return jsonify({'error': 'You must consent to data processing before submitting verification'}), 400

        ic_number = request.form.get('ic_number', '').strip()
        full_name = request.form.get('full_name', '').strip()

        if not ic_number or not full_name:
            return jsonify({'error': 'IC number and full name are required'}), 400

        if not re.match(r'^\d{12}$', ic_number):
            return jsonify({'error': 'Invalid IC number format (12 digits required)'}), 400
        
        verification_folder = os.path.join(UPLOAD_FOLDER, 'verification')
        os.makedirs(verification_folder, exist_ok=True)
        
        ic_front = ic_back = selfie = None
        
        for field, attr in [('ic_front', 'ic_front_image'), ('ic_back', 'ic_back_image'), ('selfie', 'selfie_image')]:
            if field in request.files:
                file = request.files[field]
                if file and file.filename and allowed_file(file.filename):
                    filename = secure_filename(f"{user_id}_{field}_{uuid.uuid4().hex}_{file.filename}")
                    file_path = os.path.join(verification_folder, filename)
                    # Encrypt at rest (PDPA: biometric data)
                    with open(file_path, 'wb') as fh:
                        fh.write(encrypt_bytes(file.read()))
                    if field == 'ic_front':
                        ic_front = f'/uploads/verification/{filename}'
                    elif field == 'ic_back':
                        ic_back = f'/uploads/verification/{filename}'
                    else:
                        selfie = f'/uploads/verification/{filename}'
        
        verification = IdentityVerification(
            user_id=user_id,
            ic_number=ic_number,
            full_name=full_name,
            ic_front_image=ic_front,
            ic_back_image=ic_back,
            selfie_image=selfie,
            verification_consent=True,
            verification_consent_date=datetime.utcnow(),
            consent_policy_version='1.0'
        )
        db.session.add(verification)
        db.session.commit()
        
        return jsonify({'success': True, 'message': 'Verification submitted successfully'}), 201
    except Exception as e:
        app.logger.error(f"Verification submit error: {str(e)}")
        return jsonify({'error': 'Failed to submit verification'}), 500


@app.route('/api/verification/withdraw', methods=['POST'])
@login_required
def withdraw_verification():
    """
    PDPA s.34 — Right of Correction.
    Allows a user to withdraw their pending or approved verification record
    so they can correct data and resubmit. Deletes encrypted images from disk
    and resets the verified status if previously approved.
    """
    try:
        user_id = session['user_id']
        user = User.query.get(user_id)

        verification = IdentityVerification.query.filter_by(
            user_id=user_id
        ).order_by(IdentityVerification.created_at.desc()).first()

        if not verification:
            return jsonify({'error': 'No verification record found'}), 404

        if verification.status not in ('pending', 'approved'):
            return jsonify({'error': 'Only pending or approved verifications can be withdrawn'}), 400

        prior_status = verification.status

        # Delete encrypted image files from disk (same pattern as account deletion)
        for img_path in (verification.ic_front_image, verification.ic_back_image, verification.selfie_image):
            if img_path:
                fname = img_path.replace('/uploads/verification/', '').lstrip('/')
                full_path = os.path.join(UPLOAD_FOLDER, 'verification', os.path.basename(fname))
                try:
                    if os.path.exists(full_path):
                        os.remove(full_path)
                except OSError as e:
                    app.logger.warning(f"Could not delete verification image {full_path}: {e}")

        # Audit trail
        audit = AuditLog(
            event_category='data_access',
            event_type='verification_withdrawn',
            severity='medium',
            user_id=user_id,
            username=user.username,
            ip_address=request.remote_addr,
            user_agent=request.headers.get('User-Agent', ''),
            action=f'User withdrew identity verification (was: {prior_status})',
            resource_type='identity_verification',
            resource_id=str(verification.id),
            status='success',
            request_method=request.method,
            request_path=request.path
        )
        db.session.add(audit)

        # Revoke verified badge if was approved
        if prior_status == 'approved':
            user.is_verified = False

        db.session.delete(verification)
        db.session.commit()

        return jsonify({
            'success': True,
            'message': 'Verification withdrawn. You may now resubmit with corrected information.'
        }), 200

    except Exception as e:
        db.session.rollback()
        app.logger.error(f"Verification withdraw error: {str(e)}")
        return jsonify({'error': 'Failed to withdraw verification'}), 500


