@app.route('/sitemap.xml')
def sitemap():
    """
    Generate dynamic XML sitemap for SEO
    Includes: Homepage, static pages, all active gigs
    """
    try:
        from flask import make_response

        # Build sitemap URLs
        pages = []

        # Homepage - highest priority
        pages.append({
            'loc': 'https://gighala.my/',
            'lastmod': datetime.now().strftime('%Y-%m-%d'),
            'changefreq': 'daily',
            'priority': '1.0'
        })

        # Static pages
        static_pages = [
            {'url': '/gigs', 'priority': '0.9', 'changefreq': 'hourly'},
            {'url': '/freelancers', 'priority': '0.9', 'changefreq': 'daily'},
            {'url': '/hire-freelancer', 'priority': '0.9', 'changefreq': 'monthly'},
            {'url': '/about', 'priority': '0.7', 'changefreq': 'monthly'},
            {'url': '/blog', 'priority': '0.8', 'changefreq': 'weekly'},
            {'url': '/contact', 'priority': '0.6', 'changefreq': 'monthly'},
            {'url': '/privacy', 'priority': '0.5', 'changefreq': 'yearly'},
            {'url': '/halal-compliance', 'priority': '0.8', 'changefreq': 'monthly'},
            {'url': '/gig-workers-bill', 'priority': '0.7', 'changefreq': 'monthly'},
            {'url': '/llms.txt', 'priority': '0.3', 'changefreq': 'monthly'},
        ]

        # Category freelancer pages
        try:
            main_cats = Category.query.filter(Category.slug.in_(MAIN_CATEGORY_SLUGS)).all()
            for cat in main_cats:
                static_pages.append({
                    'url': f'/freelancers/{cat.slug}',
                    'priority': '0.8',
                    'changefreq': 'weekly'
                })
        except Exception:
            pass

        # SEO hire category pages
        for hire_slug in SEO_HIRE_SLUGS:
            static_pages.append({
                'url': f'/hire/{hire_slug}',
                'priority': '0.8',
                'changefreq': 'monthly'
            })

        # SEO freelancer city pages
        for city_slug in SEO_CITY_SLUGS:
            static_pages.append({
                'url': f'/freelancers/{city_slug}',
                'priority': '0.8',
                'changefreq': 'weekly'
            })

        # SEO comparison pages
        for compare_slug in SEO_COMPARE_SLUGS:
            static_pages.append({
                'url': f'/compare/{compare_slug}',
                'priority': '0.7',
                'changefreq': 'monthly'
            })

        # Blog articles
        try:
            from blog_data import get_all_articles
            blog_posts_data = get_all_articles()
            for article in blog_posts_data:
                static_pages.append({
                    'url': f"/blog/{article.get('slug', '')}",
                    'priority': '0.7',
                    'changefreq': 'monthly'
                })
        except Exception:
            pass

        for page in static_pages:
            pages.append({
                'loc': f"https://gighala.my{page['url']}",
                'lastmod': datetime.now().strftime('%Y-%m-%d'),
                'changefreq': page['changefreq'],
                'priority': page['priority']
            })

        # All active gigs (open, in_progress, or recently updated)
        active_gigs = Gig.query.filter(
            Gig.status.in_(['open', 'in_progress', 'completed'])
        ).order_by(Gig.updated_at.desc()).limit(5000).all()

        for gig in active_gigs:
            # Determine priority based on status
            if gig.status == 'open':
                priority = '0.8'
                changefreq = 'daily'
            elif gig.status == 'in_progress':
                priority = '0.6'
                changefreq = 'weekly'
            else:  # completed
                priority = '0.4'
                changefreq = 'monthly'

            pages.append({
                'loc': f"https://gighala.my/gig/{gig.id}",
                'lastmod': gig.updated_at.strftime('%Y-%m-%d') if gig.updated_at else gig.created_at.strftime('%Y-%m-%d'),
                'changefreq': changefreq,
                'priority': priority
            })

        # Generate XML
        sitemap_xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
        sitemap_xml += '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n'

        for page in pages:
            sitemap_xml += '  <url>\n'
            sitemap_xml += f'    <loc>{page["loc"]}</loc>\n'
            sitemap_xml += f'    <lastmod>{page["lastmod"]}</lastmod>\n'
            sitemap_xml += f'    <changefreq>{page["changefreq"]}</changefreq>\n'
            sitemap_xml += f'    <priority>{page["priority"]}</priority>\n'
            sitemap_xml += '  </url>\n'

        sitemap_xml += '</urlset>'

        # Return with correct content type
        response = make_response(sitemap_xml)
        response.headers['Content-Type'] = 'application/xml; charset=utf-8'
        return response

    except Exception as e:
        app.logger.error(f"Sitemap generation error: {str(e)}")
        return 'Error generating sitemap', 500


