@app.cli.command('make-support-agent')
@click.argument('identifier')
def make_support_agent_cmd(identifier):
    """Promote an existing user to support_agent role, or create a new account.

    IDENTIFIER can be an email address or username of an existing user.
    If no matching user exists you will be prompted to create one.

    Usage:
      flask make-support-agent agent@example.com
      flask make-support-agent agentusername
    """
    import sys
    with app.app_context():
        user = User.query.filter(
            (User.email == identifier) | (User.username == identifier)
        ).first()

        if not user:
            print(f'No user found with email/username "{identifier}".')
            create = input('Create a new account? [y/N]: ').strip().lower()
            if create != 'y':
                print('Aborted.')
                sys.exit(1)
            username = input('Username: ').strip()
            email = input('Email: ').strip()
            password = input('Password: ').strip()
            full_name = input('Full name (optional): ').strip() or None
            if not username or not email or not password:
                print('Username, email, and password are required.')
                sys.exit(1)
            from werkzeug.security import generate_password_hash
            user = User(
                username=username,
                email=email,
                password_hash=generate_password_hash(password),
                full_name=full_name,
                is_verified=True,
                is_admin=True,
                admin_role='support_agent',
            )
            db.session.add(user)
            db.session.commit()
            print(f'Created support agent account: {username} ({email})')
        else:
            user.is_admin = True
            user.admin_role = 'support_agent'
            db.session.commit()
            print(f'Promoted {user.username} ({user.email}) to support_agent.')

        print(f'Done. Agent can now log in and access /admin/support.')


@app.cli.command('fix-db-permissions')
def fix_db_permissions_cmd():
    """Fix 'permission denied for table worker_specialization' errors.

    Tries four strategies in order:
      1. ALTER TABLE OWNER TO CURRENT_USER (needs superuser)
      2. GRANT ALL via same connection (needs table ownership)
      3. SET ROLE <table_owner> + GRANT (needs role membership)
      4. Use SUPERUSER_DATABASE_URL env var for elevated privileges

    Usage:
      flask fix-db-permissions
      SUPERUSER_DATABASE_URL="postgresql://postgres:pass@host/db" flask fix-db-permissions
    """
    import sys
    from urllib.parse import urlparse as _up
    from sqlalchemy import create_engine as _ce, text as _t

    database_url = app.config.get('SQLALCHEMY_DATABASE_URI', '')
    if 'sqlite' in database_url:
        print('SQLite detected – no role-based permissions, nothing to do.')
        sys.exit(0)

    _app_user = _up(database_url).username or ''
    _fix_tables = ('worker_specialization', 'worker_rate_audit', 'gig_worker', 'fractional_application')
    _fix_seqs   = ('worker_specialization_id_seq', 'worker_rate_audit_id_seq', 'gig_worker_id_seq')

    def _norm(u):
        return u.replace('postgres://', 'postgresql://', 1) if u.startswith('postgres://') else u

    def _check_access(engine):
        try:
            with engine.connect() as c:
                c.execute(_t('SELECT 1 FROM worker_specialization LIMIT 1'))
            return True
        except Exception:
            return False

    print('=' * 60)
    print('flask fix-db-permissions')
    print('=' * 60)
    print(f'App DB user : {_app_user or "(not found in URL)"}')

    # Get diagnostic info
    try:
        with db.engine.connect() as c:
            owner = c.execute(_t("SELECT tableowner FROM pg_tables WHERE tablename='worker_specialization'")).fetchone()
            cur   = c.execute(_t('SELECT current_user')).fetchone()
            print(f'Table owner : {owner[0] if owner else "TABLE NOT FOUND"}')
            print(f'Current user: {cur[0] if cur else "unknown"}')
    except Exception as e:
        print(f'Diagnostic query failed: {e}')
    print()

    if _check_access(db.engine):
        print('[OK] worker_specialization is already accessible. No action needed.')
        sys.exit(0)

    # Strategy 1: ALTER TABLE OWNER (superuser)
    print('[Strategy 1] ALTER TABLE OWNER TO CURRENT_USER …')
    try:
        with db.engine.connect() as c:
            for t in _fix_tables:
                c.execute(_t(f'ALTER TABLE {t} OWNER TO CURRENT_USER'))
            c.commit()
        if _check_access(db.engine):
            print('  Success!')
            sys.exit(0)
    except Exception as e:
        print(f'  Failed: {e}')

    # Strategy 2: GRANT via app connection (owns the table)
    print('[Strategy 2] GRANT ALL via app connection …')
    try:
        with db.engine.connect() as c:
            for t in _fix_tables:
                c.execute(_t(f'GRANT ALL ON TABLE {t} TO "{_app_user}"'))
            for s in _fix_seqs:
                try:
                    c.execute(_t(f'GRANT ALL ON SEQUENCE {s} TO "{_app_user}"'))
                except Exception:
                    pass
            c.commit()
        if _check_access(db.engine):
            print('  Success!')
            sys.exit(0)
    except Exception as e:
        print(f'  Failed: {e}')

    # Strategy 3: SET ROLE to table owner, then GRANT
    print('[Strategy 3] SET ROLE to table owner + GRANT …')
    try:
        with db.engine.connect() as c:
            row = c.execute(_t("SELECT tableowner FROM pg_tables WHERE tablename='worker_specialization'")).fetchone()
            if row:
                owner = row[0]
                print(f'  Table owner: {owner}')
                c.execute(_t(f'SET ROLE "{owner}"'))
                for t in _fix_tables:
                    c.execute(_t(f'GRANT ALL ON TABLE {t} TO "{_app_user}"'))
                for s in _fix_seqs:
                    try:
                        c.execute(_t(f'GRANT ALL ON SEQUENCE {s} TO "{_app_user}"'))
                    except Exception:
                        pass
                c.execute(_t('RESET ROLE'))
                c.commit()
        if _check_access(db.engine):
            print('  Success!')
            sys.exit(0)
    except Exception as e:
        print(f'  Failed: {e}')

    # Strategy 4: SUPERUSER_DATABASE_URL – try ALTER TABLE OWNER first
    _su_url = os.environ.get('SUPERUSER_DATABASE_URL', '').strip()
    if _su_url:
        print('[Strategy 4] ALTER TABLE OWNER via SUPERUSER_DATABASE_URL …')
        try:
            su_engine = _ce(_norm(_su_url))
            with su_engine.connect() as c:
                su_user = c.execute(_t('SELECT current_user')).scalar()
                print(f'  Superuser connected as: {su_user}')
                for t in _fix_tables:
                    c.execute(_t(f'ALTER TABLE {t} OWNER TO "{_app_user}"'))
                for s in _fix_seqs:
                    try:
                        c.execute(_t(f'ALTER SEQUENCE {s} OWNER TO "{_app_user}"'))
                    except Exception:
                        pass
                c.commit()
            if _check_access(db.engine):
                print('  Success!')
                sys.exit(0)
        except Exception as e:
            print(f'  Failed: {e}')

        # Strategy 5: DROP + recreate (nuclear, data-safe since feature was broken)
        print('[Strategy 5] DROP broken tables + recreate via SUPERUSER_DATABASE_URL …')
        print('  (worker_specialization data will be lost, but the feature was inaccessible anyway)')
        try:
            su_engine = _ce(_norm(_su_url))
            with su_engine.connect() as c:
                for stmt in (
                    'ALTER TABLE IF EXISTS gig_worker DROP CONSTRAINT IF EXISTS gig_worker_specialization_id_fkey',
                    'ALTER TABLE IF EXISTS application DROP CONSTRAINT IF EXISTS application_specialization_id_fkey',
                    'DROP TABLE IF EXISTS worker_rate_audit',
                    'DROP TABLE IF EXISTS worker_specialization',
                ):
                    try:
                        c.execute(_t(stmt))
                    except Exception:
                        c.rollback()
                c.commit()
            print('  Dropped old tables. Recreating via SQLAlchemy …')
            with app.app_context():
                db.create_all()
            if _check_access(db.engine):
                print('  Success! Tables recreated and owned by app user.')
                sys.exit(0)
            else:
                print('  Tables recreated but still cannot access – check DATABASE_URL.')
        except Exception as e:
            print(f'  Failed: {e}')
    else:
        print('[Strategy 4/5] Skipped (SUPERUSER_DATABASE_URL not set)')

    # All failed – print manual instructions
    fix = _app_user or '<app_db_user>'
    print()
    print('=' * 60)
    print('All strategies failed.')
    print()
    print('Paste this in your Railway/Neon/Supabase SQL console:')
    print('  DROP TABLE IF EXISTS worker_rate_audit;')
    print('  DROP TABLE IF EXISTS worker_specialization;')
    print('Then restart the app – it will recreate the tables correctly.')
    print()
    print('Or set SUPERUSER_DATABASE_URL and re-run: flask fix-db-permissions')
    print('=' * 60)
    sys.exit(1)


