@app.route('/api/support/ticket/<int:ticket_id>')
@login_required
def get_support_ticket(ticket_id):
    """Get a specific support ticket with messages — owner or support agent"""
    user_id = session['user_id']
    user = User.query.get(user_id)
    ticket = SupportTicket.query.get_or_404(ticket_id)
    is_agent = user and (user.is_admin or user.admin_role == 'support_agent')
    if not is_agent and ticket.user_id != user_id:
        return jsonify({'error': 'Unauthorized'}), 403
    messages = [{
        'id': m.id,
        'message': m.message,
        'is_admin_reply': m.is_admin_reply,
        'sender_name': m.sender.full_name if m.sender else 'Support Team',
        'created_at': m.created_at.isoformat() if m.created_at else None,
        'attachment_url': m.attachment_url,
        'attachment_filename': m.attachment_filename,
        'attachment_type': m.attachment_type
    } for m in ticket.messages]
    data = ticket.to_dict()
    data['messages'] = messages
    return jsonify(data)


@app.route('/api/support/ticket/<int:ticket_id>/message', methods=['POST'])
@login_required
def add_support_ticket_message(ticket_id):
    """User adds a follow-up message to their ticket"""
    user_id = session['user_id']
    ticket = SupportTicket.query.get_or_404(ticket_id)
    if ticket.user_id != user_id:
        return jsonify({'error': 'Unauthorized'}), 403
    if ticket.status in ('resolved', 'closed'):
        return jsonify({'error': 'Ticket is closed'}), 400

    # Support both JSON and multipart form data
    if request.content_type and 'multipart/form-data' in request.content_type:
        message_text = sanitize_input(request.form.get('message', ''), max_length=2000)
        attachment_url = request.form.get('attachment_url', '').strip()
        attachment_filename = request.form.get('attachment_filename', '').strip()
        attachment_type = request.form.get('attachment_type', '').strip()
    else:
        data = request.json or {}
        message_text = sanitize_input(data.get('message', ''), max_length=2000)
        attachment_url = data.get('attachment_url', '').strip()
        attachment_filename = data.get('attachment_filename', '').strip()
        attachment_type = data.get('attachment_type', '').strip()

    if not message_text and not attachment_url:
        return jsonify({'error': 'Message cannot be empty'}), 400

    msg = SupportTicketMessage(
        ticket_id=ticket_id,
        sender_id=user_id,
        message=message_text or ('[Image]' if attachment_type == 'image' else '[File]'),
        is_admin_reply=False,
        attachment_url=attachment_url or None,
        attachment_filename=attachment_filename or None,
        attachment_type=attachment_type or None
    )
    db.session.add(msg)

    if ticket.status == 'resolved':
        ticket.status = 'open'
    ticket.updated_at = datetime.utcnow()
    db.session.commit()
    return jsonify({'success': True})


@app.route('/api/support/ticket/<int:ticket_id>/poll')
@login_required
def poll_support_ticket(ticket_id):
    """Poll for new messages on a support ticket since a given timestamp.
    Used by the live chat widget for real-time feel via polling.
    Query param: since=<ISO datetime>
    """
    user_id = session['user_id']
    user = User.query.get(user_id)
    ticket = SupportTicket.query.get_or_404(ticket_id)

    is_agent = user and (user.is_admin or user.admin_role == 'support_agent')
    if not is_agent and ticket.user_id != user_id:
        return jsonify({'error': 'Unauthorized'}), 403

    since_str = request.args.get('since', '')
    try:
        since = datetime.fromisoformat(since_str) if since_str else datetime.utcnow() - timedelta(seconds=30)
    except ValueError:
        since = datetime.utcnow() - timedelta(seconds=30)

    new_messages = SupportTicketMessage.query.filter(
        SupportTicketMessage.ticket_id == ticket_id,
        SupportTicketMessage.created_at > since
    ).order_by(SupportTicketMessage.created_at).all()

    return jsonify({
        'messages': [{
            'id': m.id,
            'message': m.message,
            'is_admin_reply': m.is_admin_reply,
            'sender_name': m.sender.full_name if m.sender else 'Support Team',
            'created_at': m.created_at.isoformat(),
            'attachment_url': m.attachment_url,
            'attachment_filename': m.attachment_filename,
            'attachment_type': m.attachment_type
        } for m in new_messages],
        'status': ticket.status,
        'server_time': datetime.utcnow().isoformat()
    })


